/* BIM AI design tokens — dark chrome overrides.
 *
 * Source of truth: spec/ui-ux-redesign-v1-spec.md §9 (dark column).
 * Activated by `<html data-theme="dark">` or `<html class="dark">`.
 */

:root[data-theme='dark'],
:root.dark {
  /* §9.1 Color — semantic chrome (dark) */
  --color-background: hsl(220 14% 10%);
  --color-foreground: hsl(220 14% 92%);
  --color-surface: hsl(220 12% 13%);
  --color-surface-strong: hsl(220 12% 16%);
  --color-surface-muted: hsl(220 12% 12%);
  --color-border: hsl(220 10% 22%);
  --color-border-strong: hsl(220 10% 30%);
  --color-muted-foreground: hsl(220 10% 62%);
  --color-accent: hsl(213 95% 62%);
  --color-accent-foreground: hsl(220 18% 14%);
  --color-accent-soft: color-mix(in srgb, hsl(213 95% 62%) 18%, hsl(220 14% 10%));
  --color-success: hsl(148 50% 50%);
  --color-warning: hsl(40 90% 60%);
  --color-danger: hsl(0 80% 62%);
  --color-info: hsl(213 92% 66%);
  --color-ring: color-mix(in srgb, hsl(213 95% 62%) 38%, transparent);

  /* Dark mode flattens shadows: §9.7 — replaces shadow with a 1 px border outline. */
  --elev-0: none;
  --elev-1: 0 0 0 1px var(--color-border-strong);
  --elev-2: 0 0 0 1px var(--color-border-strong);
  --elev-3: 0 0 0 1px var(--color-border-strong);

  /* Backwards-compat aliases re-resolve under dark. */
  --background: var(--color-background);
  --foreground: var(--color-foreground);
  --surface: var(--color-surface);
  --border: var(--color-border);
  --muted-foreground: var(--color-muted-foreground);
  --accent: var(--color-accent);
  --accent-foreground: var(--color-accent-foreground);
  --ring: var(--color-ring);
}

/* Conservative preview design system — borrowed from ~/repos/hof-os.
 *
 * Wires the slate / navy enterprise tokens (serif type, tight radii)
 * onto the BIM AI shell. Drafting tokens (paper, grid, category fills)
 * still come from tokens-drafting.css since hof-os has no drafting
 * surface. To preview, flip the import in
 * packages/web/src/design-systems/default.css from
 * tokens-default.css to ./conservative/conservative.css. */

@import './tokens-conservative.css';

/* Reuse the BIM AI drafting palette so Plan + 3D canvas stays paper-like
 * even when the chrome is conservative. */
@import '../tokens-drafting.css';

